{% set ns = namespace() %}
{% set query = "project_id is '" + projectid + "' and incident_id is '" + incidentid + "' " %}
{% set incidentstream = "oia-incidents-stream" %}
{% set incident_res = engine.query_stream_data(stream=incidentstream, cfxql_query=query) %}
{% if incident_res is defined and incident_res|length > 0 %}
    {% set incident = incident_res[0] %}
    {% set incident_occurance_time = incident.get("i_cfx_incident_occurred", incident.get("i_created_ts")) %}
    {% if incident_occurance_time is string %}
        {% set _ = logger.info("Found incident_occurance_time as string hence converting it to int") %}
        {% set incident_occurance_time = incident_occurance_time | int %}
    {% endif %}
    {% set from_time = incident_occurance_time + ((-12)* 60 * 60 * 1000) %}
    {% set from_time_str = to_datetime(from_time, unit='ms').isoformat() %}
    {% set to_time =  incident_occurance_time + (4 * 60 * 60 * 1000) %}
    {% set to_time_str = to_datetime(to_time, unit='ms').isoformat() %}
    {% set config_query = "roomid is '" + projectid + "' and pagename is 'logs' " %}
    {% set config_stream = "oia-incident-page-config" %}
    {% set config_res = engine.query_stream_data(stream=config_stream, cfxql_query=config_query) %}
    {% set page_config = {} %}
    {% if config_res is defined and config_res|length > 0 %}
        {% set config_json_res = config_res[0] %}
        {% set config_json = config_json_res.get("config_json") %}
        {% set config_json_type = "string" %}
        {% if config_json is mapping and config_json is not string %}
            {% set config_json_type = "mapping" %}
        {% elif config_json is sequence and config_json is not mapping and config_json is not string %}
            {% set config_json_type = "list" %}
        {% endif %}
        {% if config_json and config_json_type == "string" %}
            {% set page_config = json_loads(config_json) %}
        {% endif %}
    {% endif %}

    {% set alert_id_values = [] %}
    {% set alert_asset_types = [] %}
    {% set ns.alert_tag_values = {} %}
    {% if page_config %}
        {% set _ = logger.debug("page_config is: " + str(page_config)) %}
        {% set alert_columns = page_config.get("alert_columns") %}
        {% if alert_columns %}
            {% set _ = logger.debug("alert_columns from page_config is: " + str(alert_columns)) %}
            {% if alert_columns.__class__.__name__ != 'list' %}
                {% set _ = logger.debug("processing alert_columns as str") %}
                {% if "," in alert_columns %}
                    {% set alert_columns = alert_columns.split(",") %}
                {% else %}
                    {% set alert_columns = [alert_columns] %}
                {% endif %}
            {% endif %}
        {% else %}
            {% set alert_columns=[] %}
        {% endif %}
        {% set _ = logger.debug("Final alert_columns is: " + str(alert_columns)) %}

        {% set alert_type_columns = page_config.get("alert_type_columns") %}
        {% if alert_type_columns %}
            {% set _ = logger.debug("alert_type_columns from page_config is: " + str(alert_type_columns)) %}
            {% if alert_type_columns.__class__.__name__ != 'list' %}
                {% set _ = logger.debug("processing alert_type_columns as str") %}
                {% if "," in alert_type_columns %}
                    {% set alert_type_columns = alert_type_columns.split(",") %}
                {% else %}
                    {% set alert_type_columns = [alert_type_columns] %}
                {% endif %}
            {% endif %}
        {% else %}
            {% set alert_type_columns=[] %}
        {% endif %}
        {% set _ = logger.debug("Final alert_type_columns is: " + str(alert_type_columns)) %}

        {% set alert_tag_columns = page_config.get("alert_tag_columns") %}
        {% if alert_tag_columns %}
            {% set _ = logger.debug("alert_tag_columns from page_config is: " + str(alert_tag_columns)) %}
            {% if alert_tag_columns.__class__.__name__ != 'list' %}
                {% set _ = logger.debug("processing alert_tag_columns as str") %}
                {% if "," in alert_tag_columns %}
                    {% set alert_tag_columns = alert_tag_columns.split(",") %}
                {% else %}
                    {% set alert_tag_columns = [alert_tag_columns] %}
                {% endif %}
            {% endif %}
        {% else %}
            {% set alert_tag_columns=[] %}
        {% endif %}
        {% set _ = logger.debug("Final alert_tag_columns is: " + str(alert_tag_columns)) %}

        {% set alert_query = "a_incident_id is '" + incidentid + "'" %}
        {% set alerts_res = engine.query_stream_data(stream="oia-alerts-stream", cfxql_query=alert_query) %}
        {% set _=logger.debug("alerts_res are: " + str(alerts_res) if alerts_res else "None") %}
        {% if alerts_res is defined %}
            {% for item in alerts_res %}
                
                {% set ns.cur_alert_ids = [] %}

                {% for alert_column in alert_columns %}
                    {% set _ = logger.debug("Going to find alert_column '" + alert_column +"' from item: " + str(item)) %}
                    {% set alert_id_val = item.get(alert_column) %}
                    {% set _ = logger.debug("found alert_id_val as: " + str(alert_id_val)) %}
                    {% if alert_id_val %}
                        {% if alert_id_val not in alert_id_values %}
                            {% set x = alert_id_values.append(alert_id_val) %}
                            {% set _ = logger.debug("From alerts added alert_id_val " + alert_id_val +" to list of eligible alert_id_values") %}
                        {% else %}
                            {% set _ = logger.debug("Found existing alert_id_val " + str(alert_id_val) +" hence skipping to add to list of eligible alert_id_values") %}
                        {% endif %}

                        {% if alert_id_val not in ns.cur_alert_ids %}
                            {% set x = ns.cur_alert_ids.append(alert_id_val) %}
                        {% endif %}
                    {% endif %}
                {% endfor %}

                {% for alert_type_column in alert_type_columns %}
                    {% set alert_type_val = item.get(alert_type_column) %}
                    {% if alert_type_val %}
                        {% if alert_type_val not in alert_asset_types %}
                            {% set x = alert_asset_types.append(alert_type_val) %}
                            {% set _ = logger.debug("From alerts added alert_type_val " + alert_type_val +" to list of eligible alert_asset_types") %}
                        {% else %}
                            {% set _ = logger.debug("Found existing alert_type_val " + alert_type_val +" hence skipping to add to list of eligible alert_asset_types") %}
                        {% endif %}
                    {% endif %}
                {% endfor %}

                {% for alert_tag_column in alert_tag_columns %}
                    {% set alert_tag_val = item.get(alert_tag_column) %}
                    {% if alert_tag_val %}
                        {% for cur_alert_id in ns.cur_alert_ids %}
                            {% if cur_alert_id not in ns.alert_tag_values %}
                                {% set x=ns.alert_tag_values.__setitem__(cur_alert_id, []) %}
                            {% endif %}
                            {% if alert_tag_val not in ns.alert_tag_values[cur_alert_id] %}
                                {% set x = ns.alert_tag_values[cur_alert_id].append(alert_tag_val) %}
                                {% set _ = logger.debug("From alerts added alert_tag_val " + alert_tag_val +" to list of eligible alert_tag_values") %}
                            {% else %}
                                {% set _ = logger.debug("Found existing alert_tag_val " + alert_tag_val +" hence skipping to add to list of eligible alert_tag_values") %}
                            {% endif %}
                        {% endfor %}        
                    {% endif %}
                {% endfor %}
            {% endfor %}
        {% else %}
            {% set _ = logger.warning("No alerts found but page config is defined to use alerts hence no metrics for incident: " + incidentid) %}
        {% endif %}

        {% if alert_id_values and alert_asset_types %}
            {% set _ = logger.info("Final alert_id_values is: " + str(alert_id_values)) %}
            {% set _ = logger.info("Final alert_asset_types is: " + str(alert_asset_types)) %}
            {% set _ = logger.info("Final alert_tag_values is: " + str(ns.alert_tag_values)) %}
            {% set widgets_config_json = page_config.get("widgets_config_json") %}
            {% set widgets_config_json_type = "string" %}
            {% if widgets_config_json is sequence and widgets_config_json is not mapping and widgets_config_json is not string %}
                {% set widgets_config_json_type = "list" %}
            {% endif %}
            {% if widgets_config_json and widgets_config_json_type == "string" %}
                {% set widgets_config_json = json_loads(widgets_config_json) %}
            {% endif %}

            {% set _ = logger.info("Final widgets_config_json is: " + ( str(widgets_config_json) if widgets_config_json else "None" )) %}
            {% if widgets_config_json%}
                {% for widgets_config in widgets_config_json %}
                    {% set _ = logger.info("going to process widgets_config: " + str(widgets_config)) %}
                    {% set asset_types = widgets_config.get("asset_types") %}
                    {% set matched_asset_types = [] %}
                    {% for asset_type in asset_types %}
                        {% if asset_type in alert_asset_types or asset_type == "*" %}
                            {% set _= matched_asset_types.append(asset_type) %}
                        {% else %}
                            {% set _ = logger.warning("No match for asset_type: '" + asset_type + "' in alert_asset_types: " + str(alert_asset_types)) %}
                        {% endif %}
                    {% endfor %}
                    {% set _ = logger.info("Final value of matched_asset_types: " + str(matched_asset_types)) %}
                    {% if matched_asset_types %}
                        {% set widgets = widgets_config.get("widgets") %}
                        {% set asset_types_str = matched_asset_types|join(",") %}
                        {% if widgets and widgets|length > 0 %}
                            {% for widget_config in widgets %}
                                {% set logs_stream = widget_config.get("logs_stream") %}
                                {% set asset_columns = widget_config.get("asset_columns") %}
                                {% set timestamp_col = widget_config.get("timestamp_col", "timestamp") %}
                                {% set extra_filter = widget_config.get("extra_filter", "") %}
                                {% set widget_type = widget_config.get("widget_type") %}
                                {% set ns.tag_columns = [] %}
                                {% if ns.alert_tag_values and asset_id in ns.alert_tag_values%}
                                    {% for tag_col in ns.alert_tag_values[asset_id] %}
                                        {% set _ = ns.tag_columns.append({"label":tag_col, "value":tag_col}) %}
                                    {% endfor %}
                                {% endif %}
                                {% for asset_id in alert_id_values%}
                                    {% set ns.data_query = "" %}
                                    {% set is_first = "true" %}
                                    {% set ns.firstAssetId = "" %}
                                    {% for asset_column in asset_columns %}
                                        {% if is_first == "true" %}
                                            {% set is_first = "false" %}
                                            {% set ns.firstAssetId = asset_id %}
                                        {% else %}
                                            {% set ns.data_query = ns.data_query + " or " %}
                                        {% endif %}
                                        {% set ns.data_query = ns.data_query + asset_column + " is '" + asset_id + "'" %}
                                        {% set timestamp_string = timestamp_col + " is after '" + str(from_time_str) + "' and " + timestamp_col + " is before '" + str(to_time_str) + "' " %}
                                        {% set ns.data_query = " ( " + ns.data_query + " ) and " + timestamp_string %}
                                        {% if extra_filter %}
                                            {% set ns.data_query = ns.data_query + " and " + extra_filter %}
                                        {% endif %}
                                        {% set _ = logger.info("Final ns.data_query is: " + str(ns.data_query)) %}

                                        {% if widget_type == "timeseries" %}
                                            {% set grouping_columns = widget_config.get("grouping_columns", []) %}
                                            {% set ns.widget = {
                                                    "title": "Logs Trend" + " - " + asset_types_str + " - " + ns.firstAssetId,
                                                    "widget_type": "timeseries",
                                                    "stream": logs_stream,
                                                    "extra_filter": ns.data_query,
                                                    "ts_column": timestamp_col,
                                                    "max_width": 12,
                                                    "height": 5,
                                                    "min_width": 12,
                                                    "fixTimeWindow": True,
                                                    "xAxisLabel": "Timestamp",
                                                    "yAxisLabel": "Count",
                                                    "static_markers": [
                                                        {
                                                            "timestamp": incident_occurance_time,
                                                            "message": "Incident Occurred",
                                                            "color": "#B71C1C",
                                                        }
                                                    ],
                                                    "chartProperties": {
                                                        "yAxisLabel": "Count",
                                                        "xAxisLabel": "Timestamp",
                                                        "legendLocation": "right"
                                                    },
                                                    "interval": "1H",
                                                    "series_spec": [
                                                        {
                                                            "column": timestamp_col,
                                                            "agg": "value_count",
                                                            "type": "float"
                                                        }
                                                    ],
                                                    "group_by": grouping_columns,
                                                    "filterTags": ns.tag_columns,
                                                    "widget_id": "timeseries - " + asset_types_str + " - " + ns.firstAssetId
                                                }
                                            %}
                                            {% set x = dashboard["dashboard_sections"][0]["widgets"].append(ns.widget) %}
                                        {% endif %}
                                        {% if widget_type == "tabular" %}
                                            {% set output_columns = widget_config.get("output_columns") %}
                                            {% set ns.widget = {
                                                    "title": "Logs" + " - " + asset_types_str + " - " + ns.firstAssetId,
                                                    "widget_type": "tabular",
                                                    "stream": logs_stream,
                                                    "extra_filter": ns.data_query,
                                                    "ts_column": timestamp_col,
                                                    "resizableColumns": True,
                                                    "timebased": False,
                                                    "remote_searchable": True,
                                                    "remote_searchable_cols": [
                                                        "message"
                                                    ],
                                                    "max_width": 12,
                                                    "height": 5,
                                                    "min_width": 12,
                                                    "columns": output_columns,
                                                    "filterTags": ns.tag_columns,
                                                    "widget_id": "tabular - " + asset_types_str + " - " + ns.firstAssetId
                                                }
                                            %}
                                            {% set x = dashboard["dashboard_sections"][0]["widgets"].append(ns.widget) %}
                                        {% endif %}
                                        {% if widget_type == "pie_chart" %}
                                            {% set widget_title_prefix = widget_config.get("widget_title_prefix") %}
                                            {% set grouping_column = widget_config.get("grouping_column") %}
                                            {% set grouping_func = widget_config.get("grouping_func") %}
                                            {% set ns.widget = {
                                                    "title": widget_title_prefix + " - " + asset_types_str + " - " + ns.firstAssetId,
                                                    "widget_type": "pie_chart",
                                                    "stream": logs_stream,
                                                    "extra_filter": ns.data_query,
                                                    "ts_column": timestamp_col,
                                                    "column": "_id",
                                                    "agg": grouping_func,
                                                    "group_by": [grouping_column],
                                                    "type": "str",
                                                    "filterTags": ns.tag_columns,
                                                    "widget_id": "pie - " + asset_types_str + " - " + ns.firstAssetId
                                                }
                                            %}
                                            {% set x = dashboard["dashboard_sections"][0]["widgets"].append(ns.widget) %}
                                        {% endif %}
                                    {% endfor %}
                                {% endfor %}
                            {% endfor %}
                        {% endif %}
                    {% else %}
                        {% set _ = logger.warning("No match found among alert_asset_types: " + str(alert_asset_types) + " and asset_types: " + str(asset_types) + " defined for widget config in page config hence skipping this widget config with matched_asset_types: " + str(matched_asset_types)) %}
                    {% endif %}
                {% endfor %}
            {% else %}
                {% set _ = logger.warning("No widget_config_json defined for page config hence no logs widgets for incident: " + incidentid) %}
            {% endif %}
        {% else %}
            {% set _ = logger.warning("No alert types or id values found but page config is defined to use alerts hence no logs for incident: " + incidentid) %}
        {% endif %}
    {% else %}
        {% set _ = logger.warning("No page_config found for logs page hence can not show logs for incident: " + incidentid) %}
    {% endif %}
{% else %}
  {% set _ = logger.warning("Can not find incident details hence can not show logs for incident: " + incidentid) %}
{% endif %}
{% set _ = logger.debug("Final logs dashboard: " + str(dashboard)) %}
